use rxbyak::*;

/// Helper: assemble instructions and return the generated bytes.
fn assemble(f: impl FnOnce(&mut CodeAssembler) -> Result<()>) -> Vec<u8> {
    let mut asm = CodeAssembler::new(4096).unwrap();
    f(&mut asm).unwrap();
    asm.code().to_vec()
}

// ─── SSE Arithmetic ────────────────────────────────────────────

#[test]
fn test_addps() {
    // addps xmm0, xmm1 → 0F 58 C1
    let code = assemble(|a| a.addps(XMM0, XMM1));
    assert_eq!(code, [0x0F, 0x58, 0xC1]);
}

