// ─── EVEX (AVX-512) ───────────────────────────────────────────

#[test]
fn test_vaddps_zmm() {
    // vaddps zmm0, zmm1, zmm2
    // EVEX.512.0F.W0 58 /r
    // 62 F1 74 48 58 C2
    // P0: R=1(80) X=1(40) B=1(20) R'=1(10) B4=0 mmm=1 → F1
    // P1: W=0 | vvvv=~1(0b1110) << 3 | 0x04 (u=1) | pp=0 → 74
    // P2: z=0 | LL=10(512) << 5 | b=0 | V'=1(8) | aaa=0 → 48
    let code = assemble(|a| a.vaddps(ZMM0, ZMM1, ZMM2));
    assert_eq!(code, [0x62, 0xF1, 0x74, 0x48, 0x58, 0xC2]);
}

