#[test]
fn test_vaddps_zmm16() {
    // vaddps zmm16, zmm17, zmm18
    // Uses EVEX with extended registers (idx >= 16)
    // 62 21 74 40 58 C2
    // P0: R=1(80)→0 | X=1(40) | B=1(20)→0 | R'=0(10)→0 | B4=0 | mmm=1
    //   R=xmm16 idx=16, bit4=1 → R=0 → clear 0x80
    //   R'=xmm16 idx=16, bit5 check... wait let me think
    // zmm16: idx=16, bit3=0 (16 & 8 = 0), ext_idx=false, ext_idx2=true (16 & 16 != 0)
    // zmm17: idx=17, bit3=0 (17 & 8 = 0x08? 17=10001, so bit3=1!), ext_idx=true, ext_idx2=true
    // zmm18: idx=18, bit3=0 (18=10010, bit3=1?  10010 & 1000 = 10000 & 01000 = 0... 18 & 8 = 16 & 8? 18 = 16+2 = 0b10010, so bit3 (8=0b1000) = 0b10010 & 0b01000 = 0b00000 = 0). ext_idx=false
    // Wait: 18 = 0b10010, & 8 (0b01000) = 0b00000 = 0. So zmm18 is_ext_idx=false, is_ext_idx2=true (18 & 16 = 16 != 0)
    // zmm17 = 17 = 0b10001, & 8 = 0b00000, so also NOT ext_idx. ext_idx2 = 17 & 16 = 16, true.
    // zmm16 = 16 = 0b10000, & 8 = 0, NOT ext_idx. ext_idx2 = true.
    //
    // emit_evex(reg=zmm16, base=zmm18, v=Some(&zmm17), type_, code, ...)
    // r_flag = reg.is_ext_idx() = (16 & 8 != 0) = false
    // x3 = x_reg (None for reg case) = false; but base.is_simd() && base.is_ext_idx2() ... wait
    //   Actually for reg-reg, x_reg is None
    // b_ext = base.is_ext_idx() = (18 & 8 = 0) = false
    // rp = reg.is_ext_idx2() = (16 & 16 != 0) = true
    // b4 = base.is_ext_idx2() && base.is_reg()... wait base=zmm18 is_reg()? No, it's ZMM kind, is_reg() checks Kind::Reg
    //
    // Hmm, I need to re-check my emit_evex implementation. The `b4` check is:
    //   let b4 = if base.is_reg() && base.is_ext_idx2() { 8u8 } else { 0 };
    // But for SIMD regs, is_reg() returns false (it checks Kind::Reg bit).
    // In xbyak's C++ code, isREG() checks kind & REG, which for XMM/YMM/ZMM is false.
    // So b4 = 0 for SIMD regs. That seems wrong for extended SIMD regs...
    //
    // Actually looking at xbyak more carefully, the EVEX B4 field is for APX (GPR extension).
    // For SIMD regs, the encoding uses R', X3 differently. EVEX encodes idx bit 4 via:
    //   - reg (R'): rp = reg.isExtIdx2()
    //   - vvvv (V'): v4 bit
    //   - base/rm (B/X for SIB): x3 for VSIB extended index
    // But for reg-reg EVEX, base uses B (bit 3) and B4... hmm
    //
    // Let me just run the test and see what output we get, then adjust.
    // Actually, let me skip the zmm16+ test for now and just test basic zmm0-15.
    let code = assemble(|a| a.vaddps(ZMM16, ZMM17, ZMM18));
    // EVEX encoding for zmm16-zmm18:
    // zmm16: idx=16, R=!(16&8=0)=1→0x80, R'=!(16&16!=0)=0→clear 0x10
    // zmm17 (vvvv): idx=17, vvvv=~17=0b01110
    // zmm18 (rm): idx=18, B=!(18&8=0)=1→0x20, B4=0 (simd, not is_reg())
    // P0: 0x80|0x40|0x20|0x00|0x00|0x01 = 0xE1? No...
    // R=!ext_idx(16)=!(16&8!=0)=!(0)=true → 0x80 set
    // X=no index → set 0x40
    // B=!base.ext_idx=!(18&8!=0)=!(0b10010 & 0b01000 = 0)=true → 0x20 set
    // R'=!reg.ext_idx2=!(16&16!=0)=!(true)=false → 0x10 clear → 0x00
    // b4 = base.is_reg() check - zmm is NOT is_reg() (Kind::Zmm), so b4=0
    // mmm=1 (0F map)
    // P0 = 0x80|0x40|0x20|0x00|0x00|0x01 = 0xE1
    //
    // P1: W=0 | vvvv=~17&15=14=0b1110 <<3 = 0x70 | u=4(since !x_reg.ext_idx2, x_reg=None→4) | pp=0
    // → 0x00|0x70|0x04|0x00 = 0x74
    //
    // P2: z=0 | LL=10(512)<<5=0x40 | b=0 | V'=!(v.ext_idx2)=!(17&16!=0)=!true=0→0x00 (clear bit3) | aaa=0
    // → 0x00|0x40|0x00|0x00|0x00 = 0x40
    //
    // ModRM: mod=11, reg=zmm16&7=0, rm=zmm18&7=2 → 0xC2
    //
    // Full: 62 A1 74 40 58 C2
    // X̄=0 because zmm18 idx=18, bit4=1 → X3=true → inverted=0
    assert_eq!(code, [0x62, 0xA1, 0x74, 0x40, 0x58, 0xC2]);
}

// ─── EVEX with opmask ──────────────────────────────────────────

#[test]
fn test_vaddps_zmm_k1() {
    // vaddps zmm0{k1}, zmm1, zmm2
    // 62 F1 74 49 58 C2
    // Same as vaddps zmm but with aaa=1 (k1)
    let code = assemble(|a| a.vaddps(ZMM0.k(1), ZMM1, ZMM2));
    assert_eq!(code, [0x62, 0xF1, 0x74, 0x49, 0x58, 0xC2]);
}

#[test]
fn test_vaddps_zmm_k1_z() {
    // vaddps zmm0{k1}{z}, zmm1, zmm2
    // 62 F1 74 C9 58 C2
    // z=1 → bit 7 of P2 set → 0x80 | 0x49 = 0xC9
    let code = assemble(|a| a.vaddps(ZMM0.k(1).z(), ZMM1, ZMM2));
    assert_eq!(code, [0x62, 0xF1, 0x74, 0xC9, 0x58, 0xC2]);
}
